<template>
  <div>
    <br />
    <span>*********  水印   ************</span><br />	
	  <input type='button' @click='addWatermark()' value='增加水印'></input>	   
    <input type='button' @click='removeWatermark()' value='删除水印'></input>
    <br />
	  <br />
	  <br />
  </div>
</template>

<script>
export default {
  name: "watermark", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      mam: { navigator: navigator },
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    /**

	添加水印
	参数说明：
		successCallback		成功回调
		errorCallback		失败回调
		content				水印  （数据类型 字符串） 

**/

    addWatermark() {
      var content = "这是水印";
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        console.log("执行到这边表示cordova环境没有准备好");
        return;
      }
      console.log("addWatermark");
      try {
        navigator.watermark.add(this.successCallback, this.errorCallback, content);
      } catch (ex) {
        console.log("try: " + ex.message);
      }
    },

    /**

	删除水印
	参数说明：
		successCallback		成功回调	"code":0 添加成功	-1 缺少关键参数
		errorCallback		失败回调	"code":1 添加失败
		content				水印  （数据类型 字符串） 

**/

    removeWatermark() {
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        console.log("执行到这边表示cordova环境没有准备好");
        return;
      }
      console.log("removeWatermark");
      try {
        navigator.watermark.remove(this.successCallback, this.errorCallback);
      } catch (ex) {
        console.log("try: " + ex.message);
      }
    },

    /**
	水印 回调
	参数说明：
		successCallback		成功回调	"code":0 添加成功	-1 缺少关键参数
**/
    successCallback(obj) {
      alert(JSON.stringify(obj));
    },
    /**
	水印 回调
	参数说明：
		errorCallback		失败回调	"code":1 添加失败
**/
    errorCallback(obj) {
      alert(JSON.stringify(obj));
    },
  },
};
</script>
<style lang='css' scoped>
/* @import url(); 引入css类 */
</style>